import numpy as np

def greedy_decode(next_logits, bos_id: int, eos_id: int, max_len: int = 50) -> list[int]:
    sequence = [bos_id]
    for _ in range(max_len):
        logits = np.asarray(next_logits(sequence))
        token = int(np.argmax(logits))
        if token == eos_id:
            break
        sequence.append(token)
    return sequence[1:]
